class Solution:
    def countSymmetricIntegers(self, low: int, high: int) -> int:
        count = 0
        for num in range(low, high + 1):
            s = str(num)
            n = len(s)
            if n % 2 != 0:
                continue
            first_half = sum(int(digit) for digit in s[:n//2])
            second_half = sum(int(digit) for digit in s[n//2:])
            if first_half == second_half:
                count += 1
        return count
